15. // UrlHandler contains the business logic for managing shortened URLs.
16. type UrlHandler struct {
17. 	urls                interfaces.UrlRepository
18. 	generator           interfaces.ShortcodeGenerator
19. 	maxUrlLen           int
20. 	minShortcodeLen     int
21. 	maxShortcodeLen     int
22. 	maxShortcodeRetries int
23. }
24. 
25. // NewUrlHandler constructs a UrlHandler.
26. // maxUrlLen, minShortcodeLen, maxShortcodeLen, and maxShortcodeRetries are read from
27. // configuration (MAX_URL_LENGTH, MIN_SHORTCODE_LENGTH, MAX_SHORTCODE_LENGTH,
28. // MAX_SHORTCODE_RETRIES) and applied during validation and shortcode generation.
29. func NewUrlHandler(urls interfaces.UrlRepository, generator interfaces.ShortcodeGenerator, maxUrlLen, minShortcodeLen, maxShortcodeLen, maxShortcodeRetries int) *UrlHandler {
30. 	return &UrlHandler{
31. 		urls:                urls,
32. 		generator:           generator,
33. 		maxUrlLen:           maxUrlLen,
34. 		minShortcodeLen:     minShortcodeLen,
35. 		maxShortcodeLen:     maxShortcodeLen,
36. 		maxShortcodeRetries: maxShortcodeRetries,
37. 	}
38. }
39. 
40. // ListUrls returns a paginated list of shortened URLs owned by userID.
41. // Returns the URL slice, the total count of matching records, and any error.
42. func (h *UrlHandler) ListUrls(ctx context.Context, userID int64, page, pageSize int) ([]*bizmodels.ShortenedUrl, int, error) {
43. 	urls, total, err := h.urls.FindByUserID(ctx, userID, page, pageSize)
44. 	if err != nil {
45. 		return nil, 0, fmt.Errorf("UrlHandler.ListUrls: %w", err)
46. 	}
47. 	return urls, total, nil
48. }
49. 
50. // CreateUrl creates a new shortened URL for the given user.
51. // If customShortcode is nil, a random Base62 shortcode is generated with up to
52. // maxShortcodeRetries retries on collision.
53. // Long URL validation and, when provided, custom shortcode validation are applied
54. // before any DB operation.
55. func (h *UrlHandler) CreateUrl(ctx context.Context, userID int64, longUrl string, customShortcode *string, expiresAt *time.Time) (*bizmodels.ShortenedUrl, error) {
56. 	if err := businesslogic.ValidateLongUrl(longUrl, h.maxUrlLen); err != nil {
57. 		return nil, err
58. 	}
59. 
60. 	if customShortcode != nil {
61. 		if err := businesslogic.ValidateCustomShortcode(*customShortcode, h.minShortcodeLen, h.maxShortcodeLen); err != nil {
62. 			return nil, err
63. 		}
64. 		record := &bizmodels.ShortenedUrl{
65. 			UserID:    userID,
66. 			Shortcode: *customShortcode,
67. 			LongUrl:   longUrl,
68. 			ExpiresAt: expiresAt,
69. 		}
70. 		created, err := h.urls.Create(ctx, record)
71. 		if err != nil {
72. 			return nil, fmt.Errorf("UrlHandler.CreateUrl: %w", err)
73. 		}
74. 		return created, nil
75. 	}
76. 
77. 	for attempt := 0; attempt < h.maxShortcodeRetries; attempt++ {
78. 		sc, err := h.generator.GenerateShortcode()
79. 		if err != nil {
80. 			return nil, fmt.Errorf("UrlHandler.CreateUrl: shortcode generation failed: %w", err)
81. 		}
82. 		record := &bizmodels.ShortenedUrl{
83. 			UserID:    userID,
84. 			Shortcode: sc,
85. 			LongUrl:   longUrl,
86. 			ExpiresAt: expiresAt,
87. 		}
88. 		created, err := h.urls.Create(ctx, record)
89. 		if err == nil {
90. 			return created, nil
91. 		}
92. 		if !errors.Is(err, businesslogic.ErrConflict) {
93. 			return nil, fmt.Errorf("UrlHandler.CreateUrl: %w", err)
94. 		}
95. 		slog.WarnContext(ctx, "shortcode collision, retrying", "attempt", attempt+1, "user_id", userID)
96. 	}
97. 
98. 	return nil, fmt.Errorf("UrlHandler.CreateUrl: %w: exhausted %d shortcode retries", businesslogic.ErrConflict, h.maxShortcodeRetries)
99. }
