19. 		OperationID: "list-user-urls",
20. 		Method:      http.MethodGet,
21. 		Path:        "/user/urls",
22. 		Summary:     "List authenticated user's shortened URLs",
23. 	}, func(ctx context.Context, input *viewmodels.ListUrlsInput) (*viewmodels.ListUrlsResponse, error) {
24. 		claims := GetJWTClaimsFromContext(ctx)
25. 		if claims == nil {
26. 			return nil, huma.NewError(http.StatusUnauthorized, "unauthorized")
27. 		}
28. 
29. 		pageSize := resolvePageSize(input.PageSize)
30. 
31. 		urls, total, err := h.ListUrls(ctx, claims.UserID, input.Page, pageSize)
32. 		if err != nil {
33. 			return nil, MapError(err)
34. 		}
35. 
36. 		return &viewmodels.ListUrlsResponse{
37. 			Body: webmappers.ListUrlsToResponse(urls, total, input.Page, pageSize),
38. 		}, nil
39. 	})
40. 
